# ══════════════════════════════════════════════════════════════════════════════
class OpticsLabGuiApp(MainFrameBase):
    """Main application window."""

    # ── init ──────────────────────────────────────────────────────────────────
    def __init__(self, parent):
        super().__init__(parent)

        # Component list and selection state
        self.components = []
        self.selected_index = -1

        # Global simulation settings
        self.global_settings = {
            'pupil_radius': 0.7,
            'z_image':      5.0,
            'auto_focus':   True,
            'z_start':     -2.0,
            'num_rays':     12,
        }

        # RGB wavelengths used for multi-colour tracing
        self.wavelengths = {
            'blue':  0.465,
            'green': 0.530,
            'red':   0.620,
        }

        # Progress gauge on toolbar
        self.gauge = wx.Gauge(self.m_toolBar1, wx.ID_ANY,
                              range=100, size=(150, -1),
                              style=wx.GA_HORIZONTAL)
        self.m_toolBar1.AddControl(self.gauge)
        self.m_toolBar1.Realize()

        # ── Sizers for the three canvas panels ────────────────────────────────
        self.canvas_sizer = wx.BoxSizer(wx.VERTICAL)
        self.m_panel_canvas_placeholder.SetSizer(self.canvas_sizer)

        self.spot_sizer = wx.BoxSizer(wx.VERTICAL)
        self.panel_SpotDiagram.SetSizer(self.spot_sizer)

        self.rayfan_sizer = wx.BoxSizer(wx.HORIZONTAL)
        self.panel_RayFanDiagram.SetSizer(self.rayfan_sizer)

        # ── 3-D optics canvas (VisPy inside wx panel) ─────────────────────────
        self.optics_canvas = OpticsLabCanvas(
            parent=self.m_panel_canvas_placeholder
        )
        self.canvas_sizer.Add(self.optics_canvas.canvas.native, 1, wx.EXPAND)
        self.optics_canvas.canvas.show()

        # Remember the "built-in" visuals so we can clear only user ones later
        self.base_visuals = set(self.optics_canvas.view.scene.children)

        # ── Extra event bindings ───────────────────────────────────────────────
        self.m_listBox_lst_components.Bind(
            wx.EVT_LISTBOX, self.m_listBox_lst_componentsOnSelect)
        self.m_listBox2.Bind(wx.EVT_LISTBOX, self.OnExampleSelect)
        self.propertyGrid_Properties.Bind(
            pg.EVT_PG_CHANGED, self.OnPropertyGridChange)

        # ── Populate built-in examples ────────────────────────────────────────
        self.m_listBox2.Append("Biconvex Lens Focus")
        self.m_listBox2.Append("Apochromatic Triplet")
        self.m_listBox2.Append("Cooke Triplet")

        # Start with empty state
        self.update_list_views()
        self.select_component(-1)
        self.m_statusBar1.SetStatusText(
            "Ready. Add a component or load a Python example to begin.")

    # ── Gauge animation ───────────────────────────────────────────────────────
    def animate_gauge(self):
        self.gauge.SetValue(0)
        for i in range(1, 101, 10):
            self.gauge.SetValue(i)
            wx.MilliSleep(30)
            wx.SafeYield()
        self.gauge.SetValue(100)
        wx.MilliSleep(50)
        self.gauge.SetValue(0)

    # ── Load default config from JSON (falls back to DEFAULT_PROPERTIES) ──────
    def _load_config(self, ctype):
        config_path = os.path.join("config", "default_lenses.json")
        try:
            with open(config_path, 'r') as f:
                return json.load(f)[ctype].copy()
        except Exception:
            return DEFAULT_PROPERTIES.get(ctype, {}).copy()

