    def m_button_btn_load_tomlOnButtonClick(self, event):
        with wx.FileDialog(
                self, "Load Optical System File",
                wildcard="TOML files (*.toml)|*.toml",
                style=wx.FD_OPEN | wx.FD_FILE_MUST_EXIST) as dlg:
            if dlg.ShowModal() == wx.ID_CANCEL:
                return
            path = dlg.GetPath()
        try:
            self.animate_gauge()
            data = self._load_toml(path)
            if 'global' in data:
                self.global_settings.update(data['global'])
            if 'components' in data:
                self.components = data['components']
            self.update_list_views()
            self.select_component(-1)
            self.rebuild_system()
            self.m_statusBar1.SetStatusText(
                f"Loaded: {os.path.basename(path)}")
        except Exception as e:
            wx.MessageBox(f"Failed to load file:\n{e}",
                          "Error", wx.OK | wx.ICON_ERROR)

    def m_button_btn_save_tomlOnButtonClick(self, event):
        with wx.FileDialog(
                self, "Save Optical System File",
                wildcard="TOML files (*.toml)|*.toml",
                style=wx.FD_SAVE | wx.FD_OVERWRITE_PROMPT) as dlg:
            if dlg.ShowModal() == wx.ID_CANCEL:
                return
            path = dlg.GetPath()
        try:
            self._save_toml(path,
                            {'global': self.global_settings,
                             'components': self.components})
            self.m_statusBar1.SetStatusText(
                f"Saved: {os.path.basename(path)}")
        except Exception as e:
            wx.MessageBox(f"Failed to save file:\n{e}",
                          "Error", wx.OK | wx.ICON_ERROR)

    def _save_toml(self, filepath, data):
        """Write a minimal TOML file from a dict with 'global' and 'components'."""
        def _fmt(v):
            if isinstance(v, str):   return f'"{v}"'
            if isinstance(v, bool):  return str(v).lower()
            return str(v)

        with open(filepath, 'w') as f:
            f.write("[global]\n")
            for k, v in data.get('global', {}).items():
                f.write(f"{k} = {_fmt(v)}\n")
            f.write("\n")
            for comp in data.get('components', []):
                f.write("[[components]]\n")
                for k, v in comp.items():
                    f.write(f"{k} = {_fmt(v)}\n")
                f.write("\n")

    def _load_toml(self, filepath):
        """Parse a minimal TOML file and return a dict."""
        data = {'global': {}, 'components': []}
        section = None
        current = {}

        with open(filepath, 'r') as f:
            for raw in f:
                line = raw.strip()
                if not line or line.startswith('#'):
                    continue
                if line == "[[components]]":
                    if section == 'components' and current:
                        data['components'].append(current)
                    current = {}
                    section = 'components'
                elif line.startswith('[') and line.endswith(']'):
                    if section == 'components' and current:
                        data['components'].append(current)
                    inner = line[1:-1]
                    if inner == 'global':
                        section = 'global'
                        current = data['global']
                else:
                    m = re.match(r'^([^=]+)=(.*)$', line)
                    if m:
                        key = m.group(1).strip()
                        vs  = m.group(2).strip()
                        if vs.startswith('"') and vs.endswith('"'):
                            val = vs[1:-1]
                        elif vs.lower() == 'true':
                            val = True
                        elif vs.lower() == 'false':
                            val = False
                        else:
                            try:
                                fval = float(vs)
                                val  = int(fval) if fval.is_integer() else fval
                            except ValueError:
                                val = vs
                        current[key] = val

        if section == 'components' and current:
            data['components'].append(current)
        return data


